import { useState } from "react";
import { createUserWithEmailAndPassword } from "firebase/auth";
import { auth, db } from "../firebase";
import { setDoc, doc, collection, query, where, getDocs } from "firebase/firestore";
import { useNavigate } from "react-router-dom";
import Swal from "sweetalert2";

export default function Cadastro() {
  const [email, setEmail] = useState("");
  const [cpf, setCpf] = useState("");
  const [senha, setSenha] = useState("");
  const [bloco, setBloco] = useState("");
  const [apartamento, setApartamento] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  // 🧮 Máscara manual de CPF (sem libs)
  const formatarCPF = (valor) => {
    return valor
      .replace(/\D/g, "") // remove tudo que não é número
      .replace(/(\d{3})(\d)/, "$1.$2")
      .replace(/(\d{3})(\d)/, "$1.$2")
      .replace(/(\d{3})(\d{1,2})$/, "$1-$2")
      .slice(0, 14); // impede digitar mais que 14 caracteres
  };

  // 🔍 Validação real de CPF
  const validarCPF = (cpf) => {
    cpf = cpf.replace(/[^\d]+/g, "");
    if (cpf.length !== 11 || /^(\d)\1+$/.test(cpf)) return false;

    let soma = 0;
    for (let i = 0; i < 9; i++) soma += parseInt(cpf.charAt(i)) * (10 - i);
    let resto = (soma * 10) % 11;
    if (resto === 10 || resto === 11) resto = 0;
    if (resto !== parseInt(cpf.charAt(9))) return false;

    soma = 0;
    for (let i = 0; i < 10; i++) soma += parseInt(cpf.charAt(i)) * (11 - i);
    resto = (soma * 10) % 11;
    if (resto === 10 || resto === 11) resto = 0;
    return resto === parseInt(cpf.charAt(10));
  };

  const handleRegister = async (e) => {
    e.preventDefault();

    // 🚫 Validação local de CPF
    if (!validarCPF(cpf)) {
      Swal.fire({
        title: "CPF inválido",
        text: "Por favor, verifique o número do CPF informado.",
        icon: "error",
        confirmButtonColor: "#ef4444",
      });
      return;
    }

    setLoading(true);

    try {
      // 🔍 Verifica se já existe um usuário com o mesmo CPF
      const usuariosRef = collection(db, "usuarios");
      const q = query(usuariosRef, where("cpf", "==", cpf));
      const querySnapshot = await getDocs(q);

      if (!querySnapshot.empty) {
        Swal.fire({
          title: "CPF já cadastrado",
          html: `
            Já existe um cadastro com este CPF.<br>
            Entre em contato com a <strong>Síndica</strong> para resolver a situação.
          `,
          icon: "warning",
          confirmButtonText: "Entendido",
          confirmButtonColor: "#4f46e5",
        });
        setLoading(false);
        return;
      }

      // 1️⃣ Cria o usuário no Firebase Auth
      const cred = await createUserWithEmailAndPassword(auth, email, senha);
      const user = cred.user;

      // 2️⃣ Cria o documento no Firestore
      await setDoc(doc(db, "usuarios", user.uid), {
        email,
        cpf,
        bloco,
        apartamento,
        ativo: 0,
        role: "user",
        criadoEm: new Date(),
      });

      // 3️⃣ Envia e-mail para o admin via EmailJS
      await fetch("https://api.emailjs.com/api/v1.0/email/send", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          service_id: "service_2yvx15e",
          template_id: "template_helk9xw",
          user_id: "tKZeCBxrG74z9O_2z",
          template_params: {
            admin_email: "gustavo.freitas1911@gmail.com",
            user_email: email,
            user_cpf: cpf,
            user_bloco: bloco,
            user_apartamento: apartamento,
          },
        }),
      });

      // 4️⃣ Popup de sucesso
      await Swal.fire({
        title: "Cadastro enviado!",
        text: "Aguarde a aprovação do administrador antes de fazer login.",
        icon: "success",
        confirmButtonText: "Entendido",
        confirmButtonColor: "#4f46e5",
        background: "#f9fafb",
        color: "#1f2937",
      });

      navigate("/");
    } catch (error) {
      console.error("Erro Firebase: ", error.code, error.message)

      let mensagem = "Verifique os dados e tenta novamente.";

      if (error.code == "auth/email-already-in-use") {
        mensagem = "Este e-mail já está cadastrado.";
      } else if (error.code == "auth/invalid-email"){
        mensagem = ("O e-mail informado é invalido.");
      } else if (error.code == "auth/weak-password"){
        mensagem = ("A senha deve ter pelo menos 6 caracteres.");
      } else if (error.code == "permission-denied"){
        mensagem = ("O aplicativo não tem permissão para salvar osdados.");
      }

      Swal.fire({
        title: "Erro ao cadastrar",
        text: mensagem,
        icon: "error",
        confirmButtonColor: "#ef4444",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-100 via-blue-50 to-indigo-100">
      <div className="w-full max-w-md p-10 rounded-3xl bg-white/40 backdrop-blur-md shadow-lg border border-white/30">
        <h1 className="text-3xl font-bold text-gray-800 mb-6 text-center">
          Cadastro<span className="text-indigo-500">.</span>
        </h1>

        <form onSubmit={handleRegister} className="flex flex-col gap-4">
          <input
            type="email"
            placeholder="E-mail"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            className="p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none"
          />

          {/* ✅ CPF com máscara manual */}
          <input
            type="text"
            placeholder="CPF"
            value={cpf}
            onChange={(e) => setCpf(formatarCPF(e.target.value))}
            maxLength={14}
            required
            className="p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none"
          />

          <input
            type="text"
            placeholder="Bloco"
            value={bloco}
            onChange={(e) => setBloco(e.target.value)}
            required
            className="p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none"
          />

          <input
            type="text"
            placeholder="Apartamento"
            value={apartamento}
            onChange={(e) => setApartamento(e.target.value)}
            required
            className="p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none"
          />

          <input
            type="password"
            placeholder="Senha"
            value={senha}
            onChange={(e) => setSenha(e.target.value)}
            required
            className="p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none"
          />

          <button
            type="submit"
            disabled={loading}
            className={`w-full py-4 rounded-xl text-white font-semibold text-lg shadow-md transition-transform transform hover:scale-[1.02] ${
              loading
                ? "bg-indigo-300 cursor-not-allowed"
                : "bg-gradient-to-r from-sky-500 to-indigo-500 hover:opacity-90"
            }`}
          >
            {loading ? "Verificando..." : "Cadastrar"}
          </button>

          <button
            type="button"
            onClick={() => navigate("/")}
            className="text-sm text-indigo-600 hover:text-indigo-700 font-medium transition mt-3"
          >
            Voltar ao login
          </button>
        </form>
      </div>
    </div>
  );
}
